<template><div class="login-page"><section class="login-visual"><div class="visual-grid"></div><div class="visual-content"><div class="visual-brand"><el-icon><FirstAidKit/></el-icon><span>NEUSOFT SMART CARE</span></div><div class="visual-copy"><span class="eyebrow">PHARMACY WORKSTATION</span><h1>让每一份处方，<br/>准确抵达患者手中</h1><p>处方智能核对、药品库存联动、发药流程留痕，构建安全高效的院内药事服务。</p><div class="trust-row"><div><strong>4 项</strong><span>发药核对</span></div><div><strong>100%</strong><span>流程留痕</span></div><div><strong>实时</strong><span>库存同步</span></div></div></div><div class="visual-foot"><span></span>云脑诊疗平台 · 药事服务中心</div></div></section><section class="login-panel"><div class="login-card"><div class="mobile-logo"><el-icon><FirstAidKit/></el-icon></div><span class="eyebrow">WELCOME BACK</span><h2>药房人员登录</h2><p>请输入工作账号，进入智慧药房工作台</p><el-form ref="formRef" :model="form" :rules="rules" label-position="top" @keyup.enter="submit"><el-form-item label="工作账号" prop="username"><el-input v-model="form.username" size="large" :prefix-icon="User" placeholder="请输入药房账号"/></el-form-item><el-form-item label="登录密码" prop="password"><el-input v-model="form.password" size="large" type="password" show-password :prefix-icon="Lock" placeholder="请输入登录密码"/></el-form-item><div class="login-options"><el-checkbox v-model="remember">记住账号</el-checkbox><span>内部系统 · 请妥善保管密码</span></div><el-button type="primary" size="large" :loading="loading" class="login-btn" @click="submit">进入药房工作台 <el-icon><Right/></el-icon></el-button></el-form><div class="login-safe"><el-icon><Lock/></el-icon>JWT 安全认证 · 操作全程记录</div></div></section></div></template>
<script setup lang="ts">import{reactive,ref}from'vue';import{useRouter}from'vue-router';import{ElMessage,type FormInstance,type FormRules}from'element-plus';import{FirstAidKit,User,Lock,Right}from'@element-plus/icons-vue';import{useAuthStore}from'@/stores/auth';const router=useRouter(),auth=useAuthStore(),formRef=ref<FormInstance>(),loading=ref(false),remember=ref(true);const form=reactive({username:localStorage.getItem('pharmacy_username')||'pharmacy01',password:'123456'});const rules:FormRules={username:[{required:true,message:'请输入工作账号',trigger:'blur'}],password:[{required:true,message:'请输入登录密码',trigger:'blur'}]};const submit=async()=>{if(!await formRef.value?.validate().catch(()=>false))return;loading.value=true;try{await auth.signIn(form.username,form.password);remember.value?localStorage.setItem('pharmacy_username',form.username):localStorage.removeItem('pharmacy_username');ElMessage.success('登录成功，欢迎回来');router.replace('/dashboard')}finally{loading.value=false}}</script>
